mapper.insert:
INSERT INTO freeboard (
board_id, member_id, category, title, content, thumbnail_url, trip_id ) VALUES (
SEQ_FREEBOARD_ID.NEXTVAL, #{memberId}, #{category}, #{title}, #{content}, #{thumbnailUrl}, #{tripId}
)

INSERT INTO freeboard_comment (
    comment_id, board_id, member_id, content
) VALUES (
    SEQ_FREEBOARD_COMMENT_ID.NEXTVAL, #{boardId}, #{memberId}, #{content}
)

mapper.update:
UPDATE freeboard 
SET like_count = like_count + #{amount} 
WHERE board_id = #{boardId}

UPDATE freeboard 
SET reply_count = reply_count - 1 
WHERE board_id = #{boardId}
